CREATE ROLE 'read_all', 'write_all', 'read_rodo', 'read_view_rodo';
GRANT SELECT ON smart_data.bank TO 'read_all';
GRANT INSERT, UPDATE, DELETE ON smart_data.bank TO 'write_all';
GRANT SELECT (id, surname, address) ON smart_data.bank TO 'read_rodo';
GRANT SELECT ON smart_data.personal_data TO 'read_view_rodo';

extra.text:
__db_prepare__ = """ CREATE DATABASE smart_data;
USE smart_data;
CREATE TABLE bank ( id INT PRIMARY KEY, surname VARCHAR(20), address VARCHAR(40), balance FLOAT, pin CHAR(4) );
INSERT INTO bank VALUES (5, 'Smith' , '4262 Grey Fox Farm Road, Houston, TX' , 2000.0 , '1337' ), (7, 'Rocky' , '1780 Bartlett Avenue, Troy, MI' , 9640.5 , '5428' ), (8, 'Svenson' , '759 Stockert Hollow Road, Redmond, WA' , 827.0 , '9822' );
CREATE VIEW personal_data AS SELECT id, surname, address FROM bank; """ invoke_cursor_sql(__db_prepare__, database=None)
invoke_cursor_sql(__student_answer__, database=None)
__sql_verify__ = """ SELECT User AS Role, Host, Db, Table_name AS 'Table/view', CASE WHEN FIND_IN_SET('Select', Table_priv) > 0 THEN 'true' ELSE 'false' END AS 'Select', CASE WHEN FIND_IN_SET('Insert', Table_priv) > 0 THEN 'true' ELSE 'false' END AS 'Insert', CASE WHEN FIND_IN_SET('Update', Table_priv) > 0 THEN 'true' ELSE 'false' END AS 'Update', CASE WHEN FIND_IN_SET('Delete', Table_priv) > 0 THEN 'true' ELSE 'false' END AS 'Delete' FROM mysql.tables_priv WHERE User IN ('read_all', 'read_rodo', 'read_view_rodo', 'write_all') AND Host = '%' ORDER BY Table_name; """ print('Tables/views privileges:\n') print(invoke_cursor_sql(__sql_verify__, database=None))
__sql_verify__ = """ SELECT User AS Role, Host, Db, Table_name AS 'Table/view', Column_name, CASE WHEN FIND_IN_SET('Select', Column_priv) > 0 THEN 'true' ELSE 'false' END AS 'Select', CASE WHEN FIND_IN_SET('Insert', Column_priv) > 0 THEN 'true' ELSE 'false' END AS 'Insert', CASE WHEN FIND_IN_SET('Update', Column_priv) > 0 THEN 'true' ELSE 'false' END AS 'Update', CASE WHEN FIND_IN_SET('Delete', Column_priv) > 0 THEN 'true' ELSE 'false' END AS 'Delete' FROM mysql.columns_priv WHERE User IN ('read_all', 'read_rodo', 'read_view_rodo', 'write_all') AND Host = '%' ORDER BY Table_name; """ print('\nColumns privileges:\n') print(invoke_cursor_sql(__sql_verify__, database=None))

