__db_prepare__ = """ CREATE USER 'andy'@'%' IDENTIFIED BY 'pazzw0Rd';
CREATE USER 'ben'@'%' IDENTIFIED BY 'pazzw0Rd';
CREATE USER 'collin'@'%' IDENTIFIED BY 'pazzw0Rd';
CREATE USER 'danny'@'%' IDENTIFIED BY 'pazzw0Rd';
CREATE DATABASE smart_data;
USE smart_data;
CREATE TABLE bank ( id INT PRIMARY KEY, surname VARCHAR(20), address VARCHAR(40), balance FLOAT, pin CHAR(4) );
INSERT INTO bank VALUES (5, 'Smith' , '4262 Grey Fox Farm Road, Houston, TX' , 2000.0 , '1337' ), (7, 'Rocky' , '1780 Bartlett Avenue, Troy, MI' , 9640.5 , '5428' ), (8, 'Svenson' , '759 Stockert Hollow Road, Redmond, WA' , 827.0 , '9822' );
CREATE VIEW personal_data AS SELECT id, surname, address FROM bank;
CREATE ROLE 'read_all', 'write_all', 'read_rodo', 'read_view_rodo';
GRANT SELECT ON smart_data.bank TO 'read_all';
GRANT INSERT, UPDATE, DELETE ON smart_data.bank TO 'write_all';
GRANT SELECT (id, surname, address) ON smart_data.bank TO 'read_rodo';
GRANT SELECT ON smart_data.personal_data TO 'read_view_rodo'; """ invoke_cursor_sql(__db_prepare__, database=None)
invoke_cursor_sql(__student_answer__, database=None)
__sql_verify__ = """ SELECT CONCAT(TO_USER, '@', TO_HOST) AS User, CONCAT(FROM_USER, '@', FROM_HOST) AS Role FROM mysql.role_edges ORDER BY User, Role; """ print('User roles:\n') print(invoke_cursor_sql(__sql_verify__, database=None))

__db_prepare__ = """
CREATE USER 'andy'@'%'
IDENTIFIED BY 'pazzw0Rd';

CREATE USER 'ben'@'%'
IDENTIFIED BY 'pazzw0Rd';

CREATE USER 'collin'@'%'
IDENTIFIED BY 'pazzw0Rd';

CREATE USER 'danny'@'%'
IDENTIFIED BY 'pazzw0Rd';

CREATE DATABASE smart_data;

USE smart_data;

CREATE TABLE bank
(
    id      INT PRIMARY KEY,
    surname VARCHAR(20),
    address VARCHAR(40),
    balance FLOAT,
    pin     CHAR(4)
);

INSERT INTO bank VALUES
(5, 'Smith'   , '4262 Grey Fox Farm Road, Houston, TX'  , 2000.0 , '1337' ),
(7, 'Rocky'   , '1780 Bartlett Avenue, Troy, MI'        , 9640.5 , '5428' ),
(8, 'Svenson' , '759 Stockert Hollow Road, Redmond, WA' ,  827.0 , '9822' );

CREATE VIEW personal_data
AS
SELECT id,
       surname,
       address
FROM   bank;

CREATE ROLE 'read_all',
            'write_all',
            'read_rodo',
            'read_view_rodo';

GRANT SELECT
   ON smart_data.bank
   TO 'read_all';

GRANT INSERT,
      UPDATE,
      DELETE
   ON smart_data.bank
   TO 'write_all';

GRANT SELECT (id, surname, address)
   ON smart_data.bank
   TO 'read_rodo';

GRANT SELECT
   ON smart_data.personal_data
   TO 'read_view_rodo';

GRANT 'read_rodo'
   TO 'andy'@'%';

GRANT 'read_all',
      'write_all'
   TO 'collin'@'%';

GRANT 'read_view_rodo'
   TO 'danny'@'%';
"""
invoke_cursor_sql(__db_prepare__, database=None)

print(invoke_cursor_sql(__student_answer__, database=None))

